def env_entity_candidate(value: str) -> bool:
    token = str(value or "").strip()
    if not token:
        return False
    slug = route_key_slug(token, fallback="entity")
    if slug in ENTITY_STOPWORDS:
        return False
    if "_" in token:
        return True
    return len(token) >= 5


